import menuData from '../menuData.json';


    let aaa;
    const rawData = menuData;
    let playOnce = true;
    
    
    if (playOnce) {
        const sortedPrice = () => {
            const priceObject = Object.keys(rawData).map((i) => rawData[i]);
            const sortedArray = priceObject.sort((a, b) => {
                return b.price - a.price
            });
            aaa = sortedArray[0];
        };
        sortedPrice();
        playOnce = false;
    }
    const data = aaa;
    

export default data;
